"use client";
import React, { useState, useRef, useEffect, Suspense, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { OrbitControls, useGLTF, Html, Environment, ContactShadows, Line } from "@react-three/drei";
import * as THREE from "three";
import { AnimatePresence, motion } from "framer-motion";

export interface Hotspot {
  id: string;
  label: string;
  title: string;
  description: string;
  position: [number, number, number];      // Coordinate on the model
  labelPosition: [number, number, number]; // Floating label coordinate in space
  cameraPos: [number, number, number];     // Target camera position
  lookAt: [number, number, number];        // Target camera look-at coordinates
}

export interface ThreeDFeatureShowcaseProps {
  modelUrl?: string;
  hotspots?: Hotspot[];
  autoRotate?: boolean;
  className?: string;
}

const DEFAULT_HOTSPOTS: Hotspot[] = [
  {
    id: "laces",
    label: "Laces",
    title: "Dynamic Fit System",
    description: "Integrated high-durability lace system designed to lock your foot in place during fast transitions.",
    position: [0.0, 0.35, 0.25],
    labelPosition: [0.65, 0.65, 0.35],
    cameraPos: [0.8, 0.4, 1.2],
    lookAt: [0.0, 0.2, 0.3],
  },
  {
    id: "sole",
    label: "Outsole",
    title: "Responsive Foam Base",
    description: "Multi-density energy returning compound offering maximum shock absorption and rebound.",
    position: [0.1, -0.3, 0.0],
    labelPosition: [0.75, -0.55, 0.25],
    cameraPos: [1.2, -0.2, 0.8],
    lookAt: [0.1, -0.3, 0.0],
  },
  {
    id: "heel",
    label: "Heel Support",
    title: "Structural Cup Frame",
    description: "Reinforced high-density heel counter holding the ankle in alignment for stability.",
    position: [-0.42, 0.05, -0.3],
    labelPosition: [-0.85, 0.35, -0.45],
    cameraPos: [-1.4, 0.3, -0.8],
    lookAt: [-0.4, 0.0, -0.2],
  },
];

// Connection line component that renders a curved Bezier dashed line in 3D WebGL space
const CurvedConnection: React.FC<{
  start: [number, number, number];
  end: [number, number, number];
  isActive: boolean;
}> = ({ start, end, isActive }) => {
  const points = useMemo(() => {
    const p0 = new THREE.Vector3(...start);
    const p2 = new THREE.Vector3(...end);
    
    // Midpoint bent upwards to create a neat arching curve
    const p1 = new THREE.Vector3().addVectors(p0, p2).multiplyScalar(0.5);
    p1.y += 0.18; 
    
    const curve = new THREE.QuadraticBezierCurve3(p0, p1, p2);
    return curve.getPoints(24);
  }, [start, end]);

  return (
    <Line
      points={points}
      color={isActive ? "#10b981" : "#a1a1aa"}
      lineWidth={1.2}
      dashed
      dashScale={30}
      dashSize={0.4}
      gapSize={0.4}
    />
  );
};

// Inner model loader component
function Model({ url, groupRef }: { url: string; groupRef: React.RefObject<THREE.Group> }) {
  const { scene } = useGLTF(url);

  useEffect(() => {
    scene.traverse((child) => {
      if ((child as THREE.Mesh).isMesh) {
        const mesh = child as THREE.Mesh;
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        
        // Ensure texture maps use standard sRGB encoding for best fidelity
        if (mesh.material) {
          const mat = mesh.material as any;
          if (mat.map) mat.map.colorSpace = THREE.SRGBColorSpace;
          if (mat.emissiveMap) mat.emissiveMap.colorSpace = THREE.SRGBColorSpace;
        }
      }
    });
  }, [scene]);

  return (
    <group ref={groupRef} dispose={null}>
      <primitive object={scene} scale={1.8} position={[0, -0.1, 0]} />
    </group>
  );
}

// Scene controller that handles camera, control-target interpolation, and parallax
function SceneController({
  activeHotspot,
  groupRef,
  controlsRef,
}: {
  activeHotspot: Hotspot | null;
  groupRef: React.RefObject<THREE.Group>;
  controlsRef: any;
}) {
  const tempCameraPos = useRef(new THREE.Vector3(1.8, 0.8, 1.8));
  const tempLookAt = useRef(new THREE.Vector3(0, 0, 0));

  useFrame((state) => {
    // 1. Mouse Parallax rotation when no hotspot is selected or during idle
    if (groupRef.current) {
      const targetRotY = state.pointer.x * 0.25;
      const targetRotX = -state.pointer.y * 0.15;
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRotY, 0.06);
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRotX, 0.06);
    }

    // 2. Camera transition logic
    if (activeHotspot) {
      const [cx, cy, cz] = activeHotspot.cameraPos;
      const [tx, ty, tz] = activeHotspot.lookAt;
      
      tempCameraPos.current.set(cx, cy, cz);
      tempLookAt.current.set(tx, ty, tz);
    } else {
      // Default overview position
      tempCameraPos.current.set(1.8, 0.8, 1.8);
      tempLookAt.current.set(0, 0, 0);
    }

    // Lerp camera position
    state.camera.position.lerp(tempCameraPos.current, 0.07);

    // Lerp controls target lookAt
    if (controlsRef.current) {
      controlsRef.current.target.lerp(tempLookAt.current, 0.07);
      controlsRef.current.update();
    }
  });

  return null;
}

export const ThreeDFeatureShowcase: React.FC<ThreeDFeatureShowcaseProps> = ({
  modelUrl = "https://raw.githubusercontent.com/KhronosGroup/glTF-Sample-Assets/main/Models/MaterialsVariantsShoe/glTF-Binary/MaterialsVariantsShoe.glb",
  hotspots = DEFAULT_HOTSPOTS,
  autoRotate = false,
  className = "",
}) => {
  const [activeHotspot, setActiveHotspot] = useState<Hotspot | null>(null);
  const groupRef = useRef<THREE.Group>(null);
  const controlsRef = useRef<any>(null);

  return (
    <div className={`relative w-full h-[600px] md:h-[700px] flex flex-col md:flex-row items-center justify-between rounded-3xl overflow-hidden bg-transparent select-none border border-zinc-200/50 dark:border-zinc-800/40 p-4 md:p-8 ${className}`}>
      
      {/* Background Dots Grid decoration */}
      <div className="absolute inset-0 pointer-events-none opacity-40 dark:opacity-20" style={{
        backgroundImage: "radial-gradient(circle, #71717a 1.2px, transparent 1.2px)",
        backgroundSize: "24px 24px"
      }} />

      {/* Title & Floating Hotspot list header */}
      <div className="absolute top-6 left-6 z-20 pointer-events-none">
        <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400 dark:text-zinc-500">Interactive 3D Engine</span>
        <h3 className="text-xl font-black text-zinc-800 dark:text-zinc-100 mt-1">Model Explorer</h3>
      </div>

      {/* Reset view overlay button */}
      {activeHotspot && (
        <button
          onClick={() => setActiveHotspot(null)}
          className="absolute top-6 right-6 z-20 px-3.5 py-1.5 rounded-full text-xs font-semibold bg-zinc-900/10 hover:bg-zinc-900/20 dark:bg-zinc-100/10 dark:hover:bg-zinc-100/20 text-zinc-800 dark:text-zinc-200 border border-zinc-200/40 dark:border-zinc-800/80 backdrop-blur-md transition-all active:scale-95 cursor-pointer"
        >
          Reset View
        </button>
      )}

      {/* 3D WebGL Canvas Area */}
      <div className="w-full h-full md:w-[65%] flex-1 relative z-10">
        <Canvas shadows camera={{ position: [1.8, 0.8, 1.8], fov: 40 }} gl={{ antialias: true }}>
          <ambientLight intensity={0.6} />
          <spotLight position={[5, 10, 5]} angle={0.3} penumbra={1} intensity={1.5} castShadow />
          <directionalLight position={[-5, 5, -5]} intensity={0.5} />
          
          <Suspense fallback={
            <Html center>
              <div className="flex items-center gap-2 bg-white/80 dark:bg-zinc-950/80 px-4 py-2 rounded-full border border-zinc-200 dark:border-zinc-800 backdrop-blur-md">
                <div className="w-4 h-4 rounded-full border-2 border-zinc-600 dark:border-zinc-400 border-t-transparent animate-spin" />
                <span className="text-xs font-medium text-zinc-800 dark:text-zinc-200">Loading model...</span>
              </div>
            </Html>
          }>
            <Model url={modelUrl} groupRef={groupRef} />
            
            {/* Live connections lines and floating markers */}
            {hotspots.map((spot) => {
              const isActive = activeHotspot?.id === spot.id;
              return (
                <group key={spot.id}>
                  {/* WebGL Curved Connection Line */}
                  <CurvedConnection start={spot.position} end={spot.labelPosition} isActive={isActive} />

                  {/* Anchor Point sphere on model */}
                  <mesh position={spot.position}>
                    <sphereGeometry args={[0.015, 16, 16]} />
                    <meshBasicMaterial color={isActive ? "#10b981" : "#ffffff"} />
                  </mesh>

                  {/* Floating HTML label at the endpoint */}
                  <Html
                    position={spot.labelPosition}
                    center
                    style={{ transition: "all 0.3s", pointerEvents: "auto" }}
                  >
                    <button
                      onClick={() => setActiveHotspot(spot)}
                      className={`px-3 py-1.5 rounded-full text-[10px] font-black tracking-wider uppercase border transition-all duration-300 backdrop-blur-md shadow-lg flex items-center gap-1.5 cursor-pointer whitespace-nowrap ${
                        isActive 
                          ? "bg-emerald-500/90 text-white border-emerald-400 shadow-emerald-500/20" 
                          : "bg-white/90 dark:bg-zinc-900/90 text-zinc-700 dark:text-zinc-300 border-zinc-200/60 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-800"
                      }`}
                    >
                      <span className={`w-1.5 h-1.5 rounded-full ${isActive ? "bg-white animate-pulse" : "bg-zinc-400 dark:bg-zinc-500"}`} />
                      <span>{spot.label}</span>
                    </button>
                  </Html>
                </group>
              );
            })}

            <Environment preset="city" />
            <ContactShadows position={[0, -0.45, 0]} opacity={0.6} scale={4.5} blur={1.8} far={1} />
          </Suspense>

          <OrbitControls
            ref={controlsRef}
            enableZoom={true}
            enablePan={false}
            minDistance={0.8}
            maxDistance={4}
            autoRotate={autoRotate && !activeHotspot}
            autoRotateSpeed={1}
          />
          <SceneController activeHotspot={activeHotspot} groupRef={groupRef} controlsRef={controlsRef} />
        </Canvas>
      </div>

      {/* Info Panel / Hotspot Controller Panel */}
      <div className="w-full md:w-[35%] flex flex-col justify-end md:justify-center gap-4 z-20 pb-4 md:pb-0 pointer-events-auto">
        <AnimatePresence mode="wait">
          {activeHotspot ? (
            <motion.div
              key={activeHotspot.id}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.35, ease: "easeInOut" }}
              className="flex flex-col gap-3 bg-white/70 dark:bg-zinc-900/70 border border-zinc-200/50 dark:border-zinc-800/60 p-6 rounded-2xl backdrop-blur-xl shadow-xl max-w-sm mx-auto md:mr-0"
            >
              <span className="self-start px-2 py-0.5 rounded text-[8px] font-bold uppercase tracking-widest bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border border-emerald-500/20">
                Details Focused
              </span>
              <h4 className="text-lg font-black text-zinc-900 dark:text-zinc-50 font-sans tracking-tight leading-tight">
                {activeHotspot.title}
              </h4>
              <p className="text-xs text-zinc-600 dark:text-zinc-400 leading-relaxed font-normal">
                {activeHotspot.description}
              </p>
            </motion.div>
          ) : (
            <motion.div
              key="overview"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.35, ease: "easeInOut" }}
              className="flex flex-col gap-4 bg-white/30 dark:bg-zinc-950/20 border border-dashed border-zinc-200/60 dark:border-zinc-800/80 p-6 rounded-2xl backdrop-blur-sm max-w-sm mx-auto md:mr-0"
            >
              <h4 className="text-md font-bold text-zinc-800 dark:text-zinc-200 leading-tight">
                Explore Product Features
              </h4>
              <p className="text-xs text-zinc-500 dark:text-zinc-500 leading-relaxed font-normal">
                Interact directly with the 3D model by clicking the pulsing hotspots to inspect high-performance elements, or drag to inspect materials.
              </p>
              
              <div className="flex flex-col gap-2 mt-2">
                {hotspots.map((spot) => (
                  <button
                    key={spot.id}
                    onClick={() => setActiveHotspot(spot)}
                    className="flex items-center justify-between px-3.5 py-2.5 rounded-xl border border-zinc-200/50 dark:border-zinc-800/40 bg-white/70 dark:bg-zinc-900/50 text-xs font-semibold text-zinc-700 dark:text-zinc-300 hover:bg-zinc-50 dark:hover:bg-zinc-800/80 hover:text-zinc-900 dark:hover:text-zinc-100 transition-all text-left cursor-pointer active:scale-98"
                  >
                    <span>{spot.title}</span>
                    <span className="text-[10px] font-black uppercase text-zinc-400 dark:text-zinc-500">→</span>
                  </button>
                ))}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

    </div>
  );
};
